example.code:
[SqliteCrudEntity]
public class UserRole
{
    [CompositeKey(Order = 0)]
    public Guid UserId { get; set; }

    [CompositeKey(Order = 1)]
    public Guid RoleId { get; set; }

    public DateTime AssignedAt { get; set; }
}

member.summary:
Gets or sets how long an idle connection may sit in the pool before being closed.
Connections used more recently than this threshold are retained (subject to
).

member.example:
In appsettings.json:

{
"Database": {
"FilePath": "/var/data/myapp.db"
}
}

In Program.cs:

var settings = builder.Configuration.GetSection(DatabaseSettings.SectionName).Get<DatabaseSettings>() ?? new DatabaseSettings();
services.AddApplicationServices(settings);

example.code:
services.AddConnectionPool("Data Source=app.db", pool =>
{
pool.MinPoolSize = 2;
pool.MaxPoolSize = 20;
pool.IdleTimeout = TimeSpan.FromMinutes(10);
});
